#!/usr/bin/env node
// Computes CSP sha256 hashes for inline executable <script> elements in the
// built site, so the fallback Content-Security-Policy in public/_headers stays
// in sync.
//
//   node bin/csp-hashes.mjs           list inline-script hashes found in the build
//   node bin/csp-hashes.mjs --check   fail if a build hash is missing from public/_headers
//
// Run a build first (npm run build:static). Production HTML normally uses the
// nonce-bearing CSP generated by functions/_middleware.ts; these hashes keep
// the static _headers fallback honest if Pages Functions are bypassed or a
// static build is inspected directly.
import fs from 'node:fs';
import path from 'node:path';
import crypto from 'node:crypto';
import { fileURLToPath } from 'node:url';

const siteRoot = path.resolve(path.dirname(fileURLToPath(import.meta.url)), '..');

// Mirror astro.config.mjs: a CF_PAGES build outputs to dist/, a local build
// to dist.nosync/. Pinning the dir avoids reading a stale dist/ left on disk.
const outDir = path.join(siteRoot, process.env.CF_PAGES ? 'dist' : 'dist.nosync');

if (!fs.existsSync(outDir)) {
  console.error(
    `csp-hashes: ${path.relative(siteRoot, outDir)}/ not found — run \`npm run build:static\` first.`,
  );
  process.exit(1);
}

function htmlFiles(dir) {
  const out = [];
  for (const entry of fs.readdirSync(dir, { withFileTypes: true })) {
    // Skip iCloud Drive conflict copies ("index 2.html", "about 3/", ...).
    if (/ \d+(\.[^.]+)?$/.test(entry.name)) continue;
    const full = path.join(dir, entry.name);
    if (entry.isDirectory()) out.push(...htmlFiles(full));
    else if (entry.name.endsWith('.html')) out.push(full);
  }
  return out;
}

// hash -> { file, snippet }
const found = new Map();

for (const file of htmlFiles(outDir)) {
  const html = fs.readFileSync(file, 'utf8');
  const re = /<script([^>]*)>([\s\S]*?)<\/script>/g;
  let match;
  while ((match = re.exec(html))) {
    const attrs = match[1];
    const body = match[2];
    if (/\bsrc=/.test(attrs)) continue; // external script — governed by host allowlist
    if (/type\s*=\s*["'][^"']*json/i.test(attrs)) continue; // data block, not script-src governed
    if (body.includes('__CF$cv$params')) continue; // Cloudflare-injected, per-request, un-hashable
    if (body.trim() === '') continue;
    const hash = 'sha256-' + crypto.createHash('sha256').update(body, 'utf8').digest('base64');
    if (!found.has(hash)) {
      found.set(hash, {
        file: path.relative(outDir, file),
        snippet: body.replace(/\s+/g, ' ').trim().slice(0, 70),
      });
    }
  }
}

const hashes = [...found.keys()].sort();

if (process.argv.includes('--check')) {
  const headers = fs.readFileSync(path.join(siteRoot, 'public/_headers'), 'utf8');
  const cspLine = headers
    .split('\n')
    .find((line) => /^\s+Content-Security-Policy:/i.test(line));

  if (!cspLine) {
    console.error('csp-hashes: no Content-Security-Policy header found in public/_headers.');
    process.exit(1);
  }

  const missing = hashes.filter((hash) => !cspLine.includes(hash));
  if (missing.length > 0) {
    console.error('STALE — public/_headers Content-Security-Policy is missing inline-script hashes:');
    for (const hash of missing) {
      console.error(`  ${hash}  (${found.get(hash).file}: ${found.get(hash).snippet})`);
    }
    console.error('Run `npm run csp:hashes` and update script-src in public/_headers.');
    process.exit(1);
  }

  console.log(`${hashes.length} inline-script hash(es) verified against public/_headers`);
} else {
  console.log(`Inline-script CSP hashes in ${path.relative(siteRoot, outDir)}:\n`);
  for (const hash of hashes) {
    const info = found.get(hash);
    console.log(`'${hash}'`);
    console.log(`  ${info.file}: ${info.snippet}\n`);
  }
  console.log('Paste the quoted values into the script-src directive in public/_headers.');
}
